1	// PIDManager handles process lifecycle for sessions: CWD-based PID discovery,
2	// ProcessWatcher registration, exit handling, and periodic liveness sweeps.
3	// It was extracted from SessionDetector to separate process management from
4	// session detection.
5	package services
6	
7	import (
8		"context"
9		"fmt"
10		"strings"
11		"sync"
12		"syscall"
13		"time"
14	
15		"irrlicht/core/domain/session"
16		"irrlicht/core/ports/outbound"
17	)
18	
19	// PIDDiscoverFunc discovers the PID owning a session. Each adapter provides
20	// its own implementation (e.g. CWD-based for Claude Code, transcript-writer
21	// for Codex/Pi). The disambiguate callback selects one PID when multiple
22	// candidates match.
23	type PIDDiscoverFunc func(cwd, transcriptPath string, disambiguate func([]int) int) (int, error)
24	
25	// PIDManager manages the process lifecycle for sessions. It discovers PIDs,
26	// registers them with ProcessWatcher, handles exits, and sweeps dead processes.
27	type PIDManager struct {
28		pw          outbound.ProcessWatcher    // optional — nil disables PID tracking
29		repo        outbound.SessionRepository // shared with SessionDetector
30		log         outbound.Logger
31		broadcaster outbound.PushBroadcaster // optional
32		readyTTL    time.Duration            // max idle time for ready sessions
33	
34		// pidDiscovers maps adapter name → PID discovery function.
35		// Nil or missing entry means no PID discovery for that adapter.
36		pidDiscovers map[string]PIDDiscoverFunc
37	
38		// onSessionDeleted is called when a session is deleted so the caller can
39		// clean up its own tracking structures (e.g. projectSessions map).
40		onSessionDeleted func(sessionID string)
41	
42		// pendingPIDs stores PIDs discovered by background goroutines, to be
43		// applied by processActivity on its next run. This avoids a race where
44		// HandlePIDAssigned's load-modify-save overwrites a state transition
45		// made by processActivity (e.g. working → ready).
46		pendingMu   sync.Mutex
47		pendingPIDs map[string]int
48	}
49	
50	// NewPIDManager creates a PIDManager with the given dependencies.
51	// pw and broadcaster may be nil (optional).
52	func NewPIDManager(
53		pw outbound.ProcessWatcher,
54		repo outbound.SessionRepository,
55		log outbound.Logger,
56		broadcaster outbound.PushBroadcaster,
57		readyTTL time.Duration,
58		pidDiscovers map[string]PIDDiscoverFunc,
59		onSessionDeleted func(sessionID string),
60	) *PIDManager {
61		return &PIDManager{
62			pw:               pw,
63			repo:             repo,
64			log:              log,
65			broadcaster:      broadcaster,
66			readyTTL:         readyTTL,
67			pidDiscovers:     pidDiscovers,
68			onSessionDeleted: onSessionDeleted,
69			pendingPIDs:      make(map[string]int),
70		}
71	}
72	
73	// HandleProcessExit deletes a session when its process exits.
74	func (pm *PIDManager) HandleProcessExit(pid int, sessionID string) {
75		if pm.onSessionDeleted != nil {
76			pm.onSessionDeleted(sessionID)
77		}
78	
79		state, err := pm.repo.Load(sessionID)
80		if err != nil || state == nil {
81			pm.log.LogInfo("process-exit", sessionID,
82				fmt.Sprintf("pid %d exited but session not found (already cleaned up)", pid))
83			return
84		}
85	
86		pm.log.LogInfo("process-exit", sessionID,
87			fmt.Sprintf("pid %d exited, deleting session (was %s)", pid, state.State))
88	
89		pm.deleteWithChildren(state)
90	}
91	
92	// deleteWithChildren removes a session and all its child sessions (subagents).
93	func (pm *PIDManager) deleteWithChildren(state *session.SessionState) {
94		if states, err := pm.repo.ListAll(); err == nil {
95			for _, s := range states {
96				if s.ParentSessionID == state.SessionID {
97					_ = pm.repo.Delete(s.SessionID)
98					pm.broadcast(outbound.PushTypeDeleted, s)
99				}
100			}
101		}
102		_ = pm.repo.Delete(state.SessionID)
103		pm.broadcast(outbound.PushTypeDeleted, state)
104	}
105	
106	// cleanupChildren removes all child sessions of the given parent.
107	func (pm *PIDManager) cleanupChildren(parentID string) {
108		states, err := pm.repo.ListAll()
109		if err != nil {
110			return
111		}
112		for _, s := range states {
113			if s.ParentSessionID == parentID {
114				_ = pm.repo.Delete(s.SessionID)
115				pm.broadcast(outbound.PushTypeDeleted, s)
116			}
117		}
118	}
119	
120	// HandlePIDAssigned records a newly-discovered PID for a session, registers it
121	// with the ProcessWatcher, and cleans up old sessions that shared the same PID.
122	//
123	// The PID is saved directly to the repo AND stored as a pending PID. The direct
124	// save ensures the PID is persisted even if no subsequent processActivity call
125	// happens. The pending PID is a safety net: if this direct save races with a
126	// concurrent processActivity and overwrites a state transition (e.g. working →
127	// ready), the next processActivity call will consume the pending PID and
128	// re-classify the state correctly.
129	func (pm *PIDManager) HandlePIDAssigned(pid int, sessionID string) {
130		if pid <= 0 {
131			return
132		}
133	
134		// Store pending PID FIRST so processActivity can correct any stale state
135		// that our direct save below might overwrite.
136		pm.pendingMu.Lock()
137		pm.pendingPIDs[sessionID] = pid
138		pm.pendingMu.Unlock()
139	
140		// Load latest state and save PID directly for immediate persistence.
141		state, _ := pm.repo.Load(sessionID)
142		if state == nil || state.PID == pid {
143			return
144		}
145	
146		state.PID = pid
147		state.UpdatedAt = time.Now().Unix()
148		_ = pm.repo.Save(state)
149	
150		// Register with ProcessWatcher for exit monitoring.
151		if pm.pw != nil {
152			if err := pm.pw.Watch(pid, sessionID); err != nil {
153				pm.log.LogError("session-detector", sessionID,
154					fmt.Sprintf("failed to watch pid %d: %v", pid, err))
155			}
156		}
157	
158		// Subagent sessions share the parent's PID, so skip cleanup when
159		// either side is a subagent.
160		if state.ParentSessionID != "" {
161			return
162		}
163	
164		// Clean up old sessions that had the same PID (e.g. /clear).
165		// A non-subagent PID can only belong to one session at a time —
166		// if a new session claims a PID, the old one is stale.
167		states, err := pm.repo.ListAll()
168		if err != nil {
169			return
170		}
171	
172		for _, old := range states {
173			if old.SessionID == sessionID || old.PID != pid {
174				continue
175			}
176			if old.ParentSessionID != "" {
177				continue
178			}
179	
180			pm.log.LogInfo("session-detector", old.SessionID,
181				fmt.Sprintf("replaced by new session %s (same pid %d) — deleting", sessionID, pid))
182	
183			if pm.onSessionDeleted != nil {
184				pm.onSessionDeleted(old.SessionID)
185			}
186	
187			_ = pm.repo.Delete(old.SessionID)
188			pm.broadcast(outbound.PushTypeDeleted, old)
189		}
190	}
191	
192	// ConsumePendingPID returns and removes a pending PID for the given session.
193	// Called by processActivity to atomically apply PID assignment during the
194	// normal state-update flow, avoiding the race with direct Save.
195	func (pm *PIDManager) ConsumePendingPID(sessionID string) (int, bool) {
196		pm.pendingMu.Lock()
197		defer pm.pendingMu.Unlock()
198		pid, ok := pm.pendingPIDs[sessionID]
199		if ok {
200			delete(pm.pendingPIDs, sessionID)
201		}
202		return pid, ok
203	}
204	
205	// claimedPIDs returns the set of PIDs already assigned to sessions other than
206	// excludeSessionID.
207	func (pm *PIDManager) claimedPIDs(excludeSessionID string) map[int]bool {
208		states, err := pm.repo.ListAll()
209		if err != nil {
210			return nil
211		}
212		claimed := make(map[int]bool)
213		for _, s := range states {
214			if s.PID > 0 && s.SessionID != excludeSessionID {
215				claimed[s.PID] = true
216			}
217		}
218		return claimed
219	}
220	
221	// TryDiscoverPID finds the PID for a session using the adapter-specific
222	// discovery function. Prefers unclaimed PIDs but falls back to already-
223	// claimed PIDs when no unclaimed candidate exists (the /clear scenario where
224	// the same process starts a new transcript). Returns true if a PID was found.
225	func (pm *PIDManager) TryDiscoverPID(sessionID, cwd, transcriptPath, adapter string) bool {
226		if pm.pw == nil {
227			return false
228		}
229		discoverFn := pm.pidDiscovers[adapter]
230		if discoverFn == nil {
231			return false
232		}
233		// Check if session already has a PID.
234		state, _ := pm.repo.Load(sessionID)
235		if state != nil && state.PID > 0 {
236			return true
237		}
238	
239		// Prefer unclaimed PIDs (multiple instances in same dir), but allow
240		// claimed PIDs when all candidates are claimed (/clear scenario).
241		claimed := pm.claimedPIDs(sessionID)
242		disambiguate := func(pids []int) int {
243			bestUnclaimed, bestAny := 0, 0
244			for _, p := range pids {
245				if p > bestAny {
246					bestAny = p
247				}
248				if !claimed[p] && p > bestUnclaimed {
249					bestUnclaimed = p
250				}
251			}
252			if bestUnclaimed > 0 {
253				return bestUnclaimed
254			}
255			return bestAny
256		}
257	
258		if pid, err := discoverFn(cwd, transcriptPath, disambiguate); err == nil && pid > 0 {
259			pm.log.LogInfo("session-detector", sessionID,
260				fmt.Sprintf("discovered pid %d for %s session", pid, adapter))
261			pm.HandlePIDAssigned(pid, sessionID)
262			return true
263		}
264		return false
265	}
266	
267	// DiscoverPIDWithRetry tries to discover a PID immediately, then retries at
268	// 500ms, 1s, 2s intervals. This covers the timing where the agent process
269	// hasn't started yet or the transcript file isn't open yet.
270	func (pm *PIDManager) DiscoverPIDWithRetry(sessionID, cwd, transcriptPath, adapter string) {
271		if pm.TryDiscoverPID(sessionID, cwd, transcriptPath, adapter) {
272			return
273		}
274		for _, delay := range []time.Duration{500 * time.Millisecond, 1 * time.Second, 2 * time.Second} {
275			time.Sleep(delay)
276			state, _ := pm.repo.Load(sessionID)
277			if state == nil || state.PID > 0 {
278				return
279			}
280			if pm.TryDiscoverPID(sessionID, cwd, transcriptPath, adapter) {
281				return
282			}
283		}
284	}
