286	// SweepDeadPIDs periodically checks all sessions for dead processes and deletes
287	// them. This is a safety net for cases where kqueue misses an exit (PID not
288	// registered, daemon restart window, race conditions). Blocks until ctx is
289	// cancelled. The sweep interval backs off from 5s to 15s when no dead PIDs
290	// are found for several consecutive sweeps.
291	func (pm *PIDManager) SweepDeadPIDs(ctx context.Context) {
292		const baseInterval = 5 * time.Second
293		const backoffInterval = 15 * time.Second
294		const cleanThreshold = 3
295	
296		ticker := time.NewTicker(baseInterval)
297		defer ticker.Stop()
298	
299		cleanSweeps := 0
300		currentInterval := baseInterval
301	
302		for {
303			select {
304			case <-ctx.Done():
305				return
306			case <-ticker.C:
307				foundDead := pm.CheckPIDLiveness()
308	
309				if foundDead {
310					cleanSweeps = 0
311				} else {
312					cleanSweeps++
313				}
314	
315				var targetInterval time.Duration
316				if cleanSweeps >= cleanThreshold {
317					targetInterval = backoffInterval
318				} else {
319					targetInterval = baseInterval
320				}
321				if targetInterval != currentInterval {
322					ticker.Reset(targetInterval)
323					currentInterval = targetInterval
324				}
325			}
326		}
327	}
328	
329	// CheckPIDLiveness checks all sessions for dead PIDs and stale state.
330	// Returns true if any dead PID was found and cleaned up.
331	func (pm *PIDManager) CheckPIDLiveness() bool {
332		states, err := pm.repo.ListAll()
333		if err != nil {
334			return false
335		}
336		foundDead := false
337		for _, state := range states {
338			if state.PID > 0 {
339				if err := syscall.Kill(state.PID, 0); err == syscall.ESRCH {
340					pm.HandleProcessExit(state.PID, state.SessionID)
341					foundDead = true
342				}
343			}
344		}
345	
346		// Sweep stale sessions that can't be cleaned up via PID liveness:
347		// - Ready sessions (idle beyond TTL)
348		// - Working/waiting sessions with PID=0 (zombies where PID discovery
349		//   failed and no kqueue/sweep cleanup path can fire)
350		// - Child sessions: ready or stale transcript (finished/zombie subagents)
351		if pm.readyTTL > 0 {
352			for _, state := range states {
353				// Child sessions: clean up immediately when ready, or when stale
354				// (transcript stopped updating — zombie from a previous run).
355				if state.ParentSessionID != "" {
356					if state.State == session.StateReady || isStaleTranscript(state.TranscriptPath) {
357						_ = pm.repo.Delete(state.SessionID)
358						pm.broadcast(outbound.PushTypeDeleted, state)
359					}
360					continue
361				}
362				// Sessions with PID=0 that are ready: the process likely exited
363				// before PID discovery succeeded. Clean up quickly (30s) rather
364				// than waiting the full readyTTL — BUT only if the transcript
365				// itself is stale. A freshly-written transcript with no PID
366				// yet means PID discovery is still catching up (e.g. Claude
367				// hasn't written ~/.claude/sessions/<pid>.json yet, or multiple
368				// claude processes share a cwd and the metadata lookup is
369				// retrying). Deleting under those conditions causes the flap
370				// loop in issue #109.
371				if state.PID == 0 && state.State == session.StateReady &&
372					time.Since(time.Unix(state.UpdatedAt, 0)) > 30*time.Second &&
373					isStaleTranscript(state.TranscriptPath) {
374					pm.log.LogInfo("session-detector", state.SessionID,
375						"ready session with no PID and stale transcript for >30s, deleting")
376					pm.deleteWithChildren(state)
377					continue
378				}
379	
380				if !state.IsStale(pm.readyTTL) {
381					continue
382				}
383				// Don't delete sessions whose process is still alive.
384				if state.PID > 0 {
385					if err := syscall.Kill(state.PID, 0); err == nil {
386						continue
387					}
388				}
389				if state.State == session.StateReady || state.PID == 0 {
390					pm.log.LogInfo("session-detector", state.SessionID,
391						fmt.Sprintf("%s session (pid=%d) idle for >%v, deleting",
392							state.State, state.PID, pm.readyTTL))
393					pm.deleteWithChildren(state)
394				}
395			}
396		}
397		return foundDead
398	}
