400	// SeedPIDs cleans up dead sessions and registers alive PIDs with ProcessWatcher
401	// during startup. Called from SessionDetector.seedFromDisk.
402	func (pm *PIDManager) SeedPIDs(states []*session.SessionState) {
403		// Track the newest session per PID for deduplication.
404		newestByPID := make(map[int]*session.SessionState)
405	
406		for _, state := range states {
407			switch {
408			case state.PID > 0:
409				if err := syscall.Kill(state.PID, 0); err == syscall.ESRCH {
410					pm.log.LogInfo("session-detector-seed", state.SessionID,
411						fmt.Sprintf("pid %d dead, deleting session", state.PID))
412					pm.deleteWithChildren(state)
413					continue
414				}
415				if pm.pw != nil {
416					if err := pm.pw.Watch(state.PID, state.SessionID); err != nil {
417						pm.log.LogError("session-detector-seed", state.SessionID,
418							fmt.Sprintf("failed to watch existing pid %d: %v", state.PID, err))
419					}
420				}
421	
422				// Track newest non-subagent session per PID for dedup below.
423				if state.ParentSessionID == "" && !strings.HasPrefix(state.SessionID, "proc-") {
424					if prev, ok := newestByPID[state.PID]; !ok || state.FirstSeen > prev.FirstSeen {
425						newestByPID[state.PID] = state
426					}
427				}
428	
429			case state.PID == 0 && state.ParentSessionID == "" && isStaleTranscript(state.TranscriptPath):
430				// Orphan from exited process (PID discovery never succeeded).
431				// Child sessions (ParentSessionID set) are exempt — they run
432				// inside the parent process and never get their own PID.
433				pm.log.LogInfo("session-detector-seed", state.SessionID,
434					"deleting orphan session")
435				pm.deleteWithChildren(state)
436			}
437		}
438	
439		// Deduplicate: when multiple non-subagent sessions share a PID (e.g.
440		// orphans left by /clear), keep only the newest one.
441		for pid, newest := range newestByPID {
442			for _, state := range states {
443				if state.PID != pid || state.SessionID == newest.SessionID {
444					continue
445				}
446				if state.ParentSessionID != "" || strings.HasPrefix(state.SessionID, "proc-") {
447					continue
448				}
449				// Verify session still exists (may have been deleted above).
450				if s, _ := pm.repo.Load(state.SessionID); s == nil {
451					continue
452				}
453				pm.log.LogInfo("session-detector-seed", state.SessionID,
454					fmt.Sprintf("duplicate pid %d (keeping %s) — deleting", pid, newest.SessionID))
455	
456				if pm.onSessionDeleted != nil {
457					pm.onSessionDeleted(state.SessionID)
458				}
459				_ = pm.repo.Delete(state.SessionID)
460				pm.broadcast(outbound.PushTypeDeleted, state)
461			}
462		}
463	
464		// Clean up stale pre-sessions (proc-*) that have a corresponding real
465		// session. Match by PID (preferred) or by adapter + CWD (for adapters
466		// like Codex whose PID discovery may not have completed yet).
467		for _, proc := range states {
468			if !strings.HasPrefix(proc.SessionID, "proc-") {
469				continue
470			}
471			if s, _ := pm.repo.Load(proc.SessionID); s == nil {
472				continue // already deleted above
473			}
474			for _, candidate := range states {
475				if strings.HasPrefix(candidate.SessionID, "proc-") || candidate.TranscriptPath == "" {
476					continue
477				}
478				matched := proc.PID > 0 && proc.PID == candidate.PID
479				if !matched && proc.CWD != "" && proc.Adapter == candidate.Adapter && proc.CWD == candidate.CWD {
480					matched = true
481				}
482				if matched {
483					pm.log.LogInfo("session-detector-seed", proc.SessionID,
484						fmt.Sprintf("pre-session superseded by %s — deleting", candidate.SessionID))
485					if pm.onSessionDeleted != nil {
486						pm.onSessionDeleted(proc.SessionID)
487					}
488					_ = pm.repo.Delete(proc.SessionID)
489					pm.broadcast(outbound.PushTypeDeleted, proc)
490					break
491				}
492			}
493		}
494	}
