496	// broadcast sends a push notification if a broadcaster is configured.
497	func (pm *PIDManager) broadcast(msgType string, state *session.SessionState) {
498		if pm.broadcaster != nil {
499			pm.broadcaster.Broadcast(outbound.PushMessage{Type: msgType, Session: state})
500		}
501	}
