1	package services
2	
3	import (
4		"sync"
5	
6		"irrlicht/core/ports/outbound"
7	)
8	
9	// PushService fans out session state changes to all subscribers.
10	// It implements ports/outbound.PushBroadcaster.
11	type PushService struct {
12		mu   sync.Mutex
13		subs []chan outbound.PushMessage
14	}
15	
16	// NewPushService creates a new PushService.
17	func NewPushService() *PushService {
18		return &PushService{}
19	}
20	
21	// Subscribe returns a new buffered channel that will receive state updates.
22	func (p *PushService) Subscribe() chan outbound.PushMessage {
23		ch := make(chan outbound.PushMessage, 16)
24		p.mu.Lock()
25		p.subs = append(p.subs, ch)
26		p.mu.Unlock()
27		return ch
28	}
29	
30	// Unsubscribe removes a subscriber channel and closes it.
31	func (p *PushService) Unsubscribe(ch chan outbound.PushMessage) {
32		p.mu.Lock()
33		defer p.mu.Unlock()
34		for i, sub := range p.subs {
35			if sub == ch {
36				p.subs = append(p.subs[:i], p.subs[i+1:]...)
37				close(ch)
38				return
39			}
40		}
41	}
42	
43	// Broadcast sends the message to all subscribers. Slow subscribers are skipped.
44	func (p *PushService) Broadcast(msg outbound.PushMessage) {
45		p.mu.Lock()
46		subs := make([]chan outbound.PushMessage, len(p.subs))
47		copy(subs, p.subs)
48		p.mu.Unlock()
49	
50		for _, ch := range subs {
51			select {
52			case ch <- msg:
53			default:
54				// skip slow subscriber
55			}
56		}
57	}
