1	package services
2	
3	import (
4		"bufio"
5		"encoding/json"
6		"os"
7		"path/filepath"
8		"time"
9	)
10	
11	// isStaleTranscript reports whether the transcript file at path has not been
12	// modified within orphanTranscriptAge. Returns false for empty paths or
13	// stat errors (file missing → not stale, will be caught elsewhere).
14	func isStaleTranscript(path string) bool {
15		if path == "" {
16			return false
17		}
18		info, err := os.Stat(path)
19		if err != nil {
20			return false
21		}
22		return time.Since(info.ModTime()) > orphanTranscriptAge
23	}
24	
25	// deriveParentSession tries all known methods to extract a parent session ID.
26	// 1. Claude Code path pattern: .../<parent-session-id>/subagents/<agent-id>.jsonl
27	// 2. Pi transcript header: {"type": "session", "parentSession": "..."}
28	func deriveParentSession(transcriptPath string) string {
29		if id := deriveParentSessionID(transcriptPath); id != "" {
30			return id
31		}
32		return deriveParentSessionFromTranscript(transcriptPath)
33	}
34	
35	// deriveParentSessionID extracts a parent session ID from a subagent transcript path.
36	// Claude Code subagent transcripts live at .../<parent-session-id>/subagents/<agent-id>.jsonl.
37	// Returns "" if the path doesn't match the subagent pattern.
38	func deriveParentSessionID(transcriptPath string) string {
39		dir := filepath.Dir(transcriptPath) // .../subagents
40		if filepath.Base(dir) != "subagents" {
41			return ""
42		}
43		return filepath.Base(filepath.Dir(dir)) // parent session ID
44	}
45	
46	// deriveParentSessionFromTranscript reads the first line of a Pi transcript
47	// and extracts the parentSession field from the session header.
48	// Returns "" if the transcript is not Pi format or has no parent session.
49	func deriveParentSessionFromTranscript(transcriptPath string) string {
50		if transcriptPath == "" {
51			return ""
52		}
53		f, err := os.Open(transcriptPath)
54		if err != nil {
55			return ""
56		}
57		defer f.Close()
58	
59		scanner := bufio.NewScanner(f)
60		if !scanner.Scan() {
61			return ""
62		}
63		var header map[string]interface{}
64		if err := json.Unmarshal(scanner.Bytes(), &header); err != nil {
65			return ""
66		}
67		if header["type"] != "session" {
68			return ""
69		}
70		if parent, ok := header["parentSession"].(string); ok && parent != "" {
71			return parent
72		}
73		return ""
74	}
75	
76	// extractProjectDir extracts the project directory name from a transcript path.
77	// Expected format: .../<project-dir>/<session-id>.jsonl
78	func extractProjectDir(transcriptPath string) string {
79		if transcriptPath == "" {
80			return ""
81		}
82		// filepath.Dir gives us the directory containing the file,
83		// filepath.Base of that gives us the project directory name.
84		dir := filepath.Dir(transcriptPath)
85		if dir == "." || dir == "/" {
86			return ""
87		}
88		return filepath.Base(dir)
89	}
