1	// OrchestratorMonitor subscribes to OrchestratorWatchers and broadcasts
2	// state updates via PushBroadcaster. It mirrors SessionDetector's pattern
3	// for the orchestrator category of inbound adapters.
4	package services
5	
6	import (
7		"context"
8		"fmt"
9		"sync"
10	
11		"irrlicht/core/domain/orchestrator"
12		"irrlicht/core/ports/inbound"
13		"irrlicht/core/ports/outbound"
14	)
15	
16	// OrchestratorMonitor watches all OrchestratorWatchers and broadcasts
17	// state updates to WebSocket clients.
18	type OrchestratorMonitor struct {
19		watchers    []inbound.OrchestratorWatcher
20		broadcaster outbound.PushBroadcaster
21		log         outbound.Logger
22	
23		mu     sync.RWMutex
24		states map[string]*orchestrator.State // name → latest state
25	}
26	
27	// NewOrchestratorMonitor creates a monitor for the given orchestrator watchers.
28	func NewOrchestratorMonitor(
29		watchers []inbound.OrchestratorWatcher,
30		broadcaster outbound.PushBroadcaster,
31		log outbound.Logger,
32	) *OrchestratorMonitor {
33		return &OrchestratorMonitor{
34			watchers:    watchers,
35			broadcaster: broadcaster,
36			log:         log,
37			states:      make(map[string]*orchestrator.State),
38		}
39	}
40	
41	// State returns the latest state for the given orchestrator name, or nil.
42	func (m *OrchestratorMonitor) State(name string) *orchestrator.State {
43		m.mu.RLock()
44		defer m.mu.RUnlock()
45		if s, ok := m.states[name]; ok {
46			cp := *s
47			return &cp
48		}
49		return nil
50	}
51	
52	// Run subscribes to all OrchestratorWatcher event streams, fans them into a
53	// single channel, and broadcasts updates. It blocks until ctx is cancelled.
54	func (m *OrchestratorMonitor) Run(ctx context.Context) error {
55		if len(m.watchers) == 0 {
56			<-ctx.Done()
57			return ctx.Err()
58		}
59	
60		merged := make(chan orchestrator.State, 4)
61		var wg sync.WaitGroup
62	
63		for _, w := range m.watchers {
64			ch := w.Subscribe()
65			wg.Add(1)
66			go func(watcher inbound.OrchestratorWatcher, ch <-chan orchestrator.State) {
67				defer wg.Done()
68				defer watcher.Unsubscribe(ch)
69				for {
70					select {
71					case <-ctx.Done():
72						return
73					case state, ok := <-ch:
74						if !ok {
75							return
76						}
77						select {
78						case merged <- state:
79						case <-ctx.Done():
80							return
81						}
82					}
83				}
84			}(w, ch)
85		}
86	
87		go func() {
88			wg.Wait()
89			close(merged)
90		}()
91	
92		m.log.LogInfo("orchestrator-monitor", "", fmt.Sprintf("started — watching %d orchestrator(s)", len(m.watchers)))
93	
94		for {
95			select {
96			case <-ctx.Done():
97				return ctx.Err()
98			case state, ok := <-merged:
99				if !ok {
100					return nil
101				}
102				m.mu.Lock()
103				cp := state
104				m.states[state.Adapter] = &cp
105				m.mu.Unlock()
106	
107				if m.broadcaster != nil {
108					m.broadcaster.Broadcast(outbound.PushMessage{
109						Type:         outbound.PushTypeOrchestratorState,
110						Orchestrator: &state,
111					})
112				}
113			}
114		}
115	}
